const handleSubmit = async (e) => {
  e.preventDefault();

  const newCapsule = { title, openDate: date, description: content };
  const token = localStorage.getItem("token"); // Get token from storage

  try {
    const response = await fetch(`${API_URL}/api/memoryhaven`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${token}` // ✅ Add the token
      },
      body: JSON.stringify(newCapsule),
    });

    if (response.ok) {
      setMessage("Capsule created successfully!");
      setTitle("");
      setDate("");
      setContent("");
    } else {
      const errorData = await response.json(); // Read error message
      setMessage(errorData.message || "Error creating capsule.");
    }
  } catch (error) {
    console.error("Error:", error);
    setMessage("Server error. Try again later.");
  }
};
